  ('elementary-0489de64-moex-00015', 'elementary-0489de64', 'elementary-0489de64-moex-114-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列有關我國捷運系統之敘述何者正確？', '["高雄輕軌與捷運紅橘線皆採取BOT方式興建與營運", "桃園機場捷運是我國首條同時連結高鐵與國際機場之捷運", "臺中捷運綠線係由臺北市政府捷運工程局興建，由臺中捷運公司營運", "目前我國六都皆至少有一條捷運路線進行營運"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "c174667e9ba2", "answer_pdf_sha1": "f5f14ba1000c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
